<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Bouncing Ball Physics Playground</title>
    <style>
        :root {
            --bg-color: #1a1a1a;
            --text-color: #e0e0e0;
            --accent-color: #4CAF50;
            --btn-bg: #333;
            --btn-hover: #444;
        }

        body {
            margin: 0;
            padding: 0;
            background-color: var(--bg-color);
            color: var(--text-color);
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            min-height: 100vh;
            overflow: hidden;
        }

        #controls {
            margin-bottom: 15px;
            display: flex;
            gap: 10px;
        }

        button {
            padding: 8px 16px;
            border: none;
            border-radius: 4px;
            background-color: var(--btn-bg);
            color: var(--text-color);
            cursor: pointer;
            font-size: 14px;
            font-weight: bold;
            transition: background-color 0.2s;
        }

        button:hover {
            background-color: var(--btn-hover);
        }

        #sim {
            background-color: #222;
            border: 2px solid #444;
            box-shadow: 0 10px 30px rgba(0,0,0,0.5);
            cursor: crosshair;
            /* Ensure at least 400x400 */
            min-width: 400px;
            min-height: 400px;
        }

        .instruction {
            margin-top: 10px;
            font-size: 0.9rem;
            color: #888;
        }
    </style>
</head>
<body>

    <div id="controls">
        <button id="drop">Drop Ball</button>
        <button id="play">Play/Pause</button>
        <button id="clear">Clear All</button>
    </div>

    <canvas id="sim" width="800" height="600"></canvas>

    <div class="instruction">Click anywhere on the canvas to add a ball.</div>

<script>
    // --- Configuration ---
    const CONFIG = {
        gravity: 0.25,
        friction: 0.99, // Air resistance
        bounceFactor: 0.8, // Energy loss on wall collision
        minRadius: 10,
        maxRadius: 30
    };

    // --- State ---
    const canvas = document.getElementById('sim');
    const ctx = canvas.getContext('2d');

    let width = canvas.width;
    let height = canvas.height;

    let balls = [];
    let isPlaying = true;
    let animationId = null;

    // --- API Implementation ---

    // Expose simulation object to window for grading harness
    window.sim = {
        get w() { return width; },
        get h() { return height; },

        balls: function() {
            return balls;
        },

        addBall: function(x, y, vx, vy, r) {
            // Default values if not provided
            const radius = r || Math.floor(Math.random() * (CONFIG.maxRadius - CONFIG.minRadius + 1)) + CONFIG.minRadius;

            // Clamp initial position to be inside canvas
            x = Math.max(radius, Math.min(width - radius, x));
            y = Math.max(radius, Math.min(height - radius, y));

            balls.push({
                x: x,
                y: y,
                vx: vx || (Math.random() - 0.5) * 10, // Random slight horizontal velocity
                vy: vy || 0,
                r: radius,
                color: `hsl(${Math.random() * 360}, 70%, 60%)`
            });

            // If paused, step once to show the new ball immediately
            if (!isPlaying) {
                window.sim.step();
            }
        },

        clear: function() {
            balls = [];
            if (animationId) cancelAnimationFrame(animationId);
            draw();
        },

        step: function(dt = 1) {
            // Update physics for all balls
            balls.forEach(ball => {
                // Apply gravity
                ball.vy += CONFIG.gravity;

                // Apply friction
                ball.vx *= CONFIG.friction;
                ball.vy *= CONFIG.friction;

                // Update position
                ball.x += ball.vx;
                ball.y += ball.vy;

                // Floor Collision
                if (ball.y + ball.r > height) {
                    ball.y = height - ball.r;
                    ball.vy *= -CONFIG.bounceFactor;
                }
                // Ceiling Collision
                else if (ball.y - ball.r < 0) {
                    ball.y = ball.r;
                    ball.vy *= -CONFIG.bounceFactor;
                }

                // Right Wall Collision
                if (ball.x + ball.r > width) {
                    ball.x = width - ball.r;
                    ball.vx *= -CONFIG.bounceFactor;
                }
                // Left Wall Collision
                else if (ball.x - ball.r < 0) {
                    ball.x = ball.r;
                    ball.vx *= -CONFIG.bounceFactor;
                }
            });

            draw();
        }
    };

    // --- Rendering ---

    function draw() {
        // Clear canvas
        ctx.clearRect(0, 0, width, height);

        // Draw balls
        balls.forEach(ball => {
            ctx.beginPath();
            ctx.arc(ball.x, ball.y, ball.r, 0, Math.PI * 2);
            ctx.fillStyle = ball.color;
            ctx.fill();

            // Optional: subtle border
            ctx.strokeStyle = "rgba(255,255,255,0.3)";
            ctx.lineWidth = 1;
            ctx.stroke();
        });
    }

    // --- Interaction & Loop ---

    function loop() {
        if (isPlaying) {
            window.sim.step();
        }
        animationId = requestAnimationFrame(loop);
    }

    // Event Listeners

    // Play/Pause Toggle
    document.getElementById('play').addEventListener('click', () => {
        isPlaying = !isPlaying;
        if (isPlaying) loop();
        else cancelAnimationFrame(animationId);
    });

    // Clear Button
    document.getElementById('clear').addEventListener('click', () => {
        window.sim.clear();
    });

    // Drop Button
    document.getElementById('drop').addEventListener('click', () => {
        // Add a ball at the center with zero velocity (it will fall)
        const r = Math.floor(Math.random() * 20) + 15;
        window.sim.addBall(width / 2, height / 2, 0, 0, r);
    });

    // Canvas Click to Add Ball
    canvas.addEventListener('mousedown', (e) => {
        const rect = canvas.getBoundingClientRect();
        const x = e.clientX - rect.left;
        const y = e.clientY - rect.top;

        window.sim.addBall(x, y, 0, 0); // Drop from click position
    });

    // Handle Resize (optional robustness)
    window.addEventListener('resize', () => {
        width = canvas.width;
        height = canvas.height;
        window.sim.clear();
    });

    // Initial Draw
    draw();

</script>
</body>
</html>
